const loadGatewayUser = async (req, res, next) => {
  try {
    // session_check
    if (!req.session?.userId) {
      return next(new Error('No session'));
    }

    // db.findUser
    const user = await db.findUser(req.session.userId);
    if (!user) {
      return next(new Error('User not found'));
    }

    // flags.load
    const flags = await flags.load(user.id);
    user.flags = flags;

    // audit.log
    await audit.log('gateway_user_loaded', { userId: user.id });

    req.user = user;
    next();
  } catch (err) {
    next(err);
  }
};
